using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// A source-generated context that only knows about Person.
[JsonSerializable(typeof(Person))]
partial class MyContext : JsonSerializerContext { }

record Person(string Name, int Age);
record Animal(string Species);

// Wire up options to use the limited source-generated resolver.
var options = new JsonSerializerOptions { TypeInfoResolver = MyContext.Default };

// 1. Strongly-typed retrieval — GetTypeInfo<T>() returns JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"Person property count : {personInfo.Properties.Count}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized with typed info: {json}");

// 2. Probe without throwing — TryGetTypeInfo returns false instead of an exception.
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
{
    // Safe downcast once we know it's available.
    var typed = (JsonTypeInfo<Person>)found!;
    Console.WriteLine($"✓ Metadata available for {typed.Type.Name}");
}

if (options.TryGetTypeInfo(typeof(Animal), out _))
{
    Console.WriteLine("✓ Metadata available for Animal");
}
else
{
    Console.WriteLine("✗ No metadata for Animal — no exception thrown");
}

